import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"4.3.药物疲劳","description":"","frontmatter":{},"headers":[],"relativePath":"1.基础规则/4.不良状态/4.3.药物疲劳.md","filePath":"1.基础规则/4.不良状态/4.3.药物疲劳.md"}'),_={name:"1.基础规则/4.不良状态/4.3.药物疲劳.md"};function d(l,a,i,p,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"_4-3-药物疲劳",tabindex:"-1"},[s("4.3.药物疲劳 "),e("a",{class:"header-anchor",href:"#_4-3-药物疲劳","aria-label":'Permalink to "4.3.药物疲劳"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新秩序000")])])],-1),o('<h1 id="药物疲劳" tabindex="-1">药物疲劳 <a class="header-anchor" href="#药物疲劳" aria-label="Permalink to &quot;药物疲劳&quot;">​</a></h1><p>药物疲劳</p><p>使用过多的药物会引起个体本身进入药物疲劳状态，在15分钟内连续食用/饮用/注射同种或不同种药物两次以上时，人物就将开始陷入药物疲劳状态，使用两次以上且不超过四次时，将进入第一阶段药物疲劳状态之中，此后每多使用两次就会上升一档（在首次使用时便立即上升），药物疲劳会导致药物本身的效力大打折扣，还会引起部分副作用，大部分的药物都会有药物疲劳效果，具体效果会在药物下标明<br> 通常情况下，药物疲劳状态对于一种价值250分的一次性药物而言，以如下效果对应每一档药物疲劳带来的副作用<br> 一档：药效降低25%<br> 二档：药效降低50%<br> 三档：药效降低75%<br> 四档：药效完全失效</p><hr><p>Copyright © 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',5)])])}const m=r(_,[["render",d]]);export{f as __pageData,m as default};
